fun matrixChainOrder(dims: IntArray): Int {
    val n = dims.size - 1 // number of matrices

    if (n <= 0) return 0

    val m = Array(n) { IntArray(n) }

    for (chainLen in 2..n) {
        for (i in 0..n - chainLen) {
            val j = i + chainLen - 1
            m[i][j] = Int.MAX_VALUE
