                val cost = m[i][k] + m[k + 1][j] +
                           dims[i] * dims[k + 1] * dims[j + 1]
                if (cost < m[i][j]) {
                    m[i][j] = cost
                }
            }
        }
    }

    return m[0][n - 1]
}

